function twoSum(nums: number[], target: number): number[] {
    const map = new Map<number, number>();
    for (let i = 0; i < nums.length; i++) {
        const complement = target - nums[i];
        if (map.has(complement)) {
            return [map.get(complement)!, i];
        }
        map.set(nums[i], i);
    }
    return [];
}

function debounce<T extends (...args: unknown[]) => void>(
    fn: T,
    delay: number
): (...args: Parameters<T>) => void {
    let timer: ReturnType<typeof setTimeout>;
    return (...args: Parameters<T>) => {
        clearTimeout(timer);
        timer = setTimeout(() => fn(...args), delay);
    };
}

function binarySearch<T>(
    arr: T[],
    target: T,
    compare: (a: T, b: T) => number
): number {
    let left = 0;
    let right = arr.length - 1;
    while (left <= right) {
        const mid = Math.floor((left + right) / 2);
        const cmp = compare(arr[mid], target);
        if (cmp === 0) return mid;
        if (cmp < 0) left = mid + 1;
        else right = mid - 1;
    }
    return -1;
}

interface ListNode<T> {
    val: T;
    next: ListNode<T> | null;
}

function reverseList<T>(head: ListNode<T> | null): ListNode<T> | null {
    let prev: ListNode<T> | null = null;
    let curr = head;
    while (curr) {
        const next = curr.next;
        curr.next = prev;
        prev = curr;
        curr = next;
    }
    return prev;
}

function validParentheses(s: string): boolean {
    const stack: string[] = [];
    const pairs: Record<string, string> = {
        ')': '(',
        '}': '{',
        ']': '[',
    };
    for (const c of s) {
        if ('({['.includes(c)) {
            stack.push(c);
        } else if (stack[stack.length - 1] !== pairs[c]) {
            return false;
        } else {
            stack.pop();
        }
    }
    return stack.length === 0;
}

function deepClone<T>(obj: T): T {
    if (obj === null || typeof obj !== 'object') return obj;
    if (Array.isArray(obj)) return (obj as unknown[]).map(deepClone) as unknown as T;
    const clone = {} as T;
    for (const key of Object.keys(obj as object) as (keyof T)[]) {
        clone[key] = deepClone((obj as T)[key]);
    }
    return clone;
}

type Listener<T> = (data: T) => void;

class EventEmitter<Events extends Record<string, unknown>> {
    private listeners = new Map<keyof Events, Listener<unknown>[]>();

    on<K extends keyof Events>(event: K, listener: Listener<Events[K]>): void {
        const handlers = this.listeners.get(event) ?? [];
        this.listeners.set(event, [...handlers, listener as Listener<unknown>]);
    }

    emit<K extends keyof Events>(event: K, data: Events[K]): void {
        this.listeners.get(event)?.forEach(fn => fn(data));
    }

    off<K extends keyof Events>(event: K, listener: Listener<Events[K]>): void {
        const handlers = this.listeners.get(event) ?? [];
        this.listeners.set(event, handlers.filter(fn => fn !== listener));
    }
}

type Result<T, E = Error> =
    | { ok: true; value: T }
    | { ok: false; error: E };

function ok<T>(value: T): Result<T> {
    return { ok: true, value };
}

function err<E = Error>(error: E): Result<never, E> {
    return { ok: false, error };
}

