async function retry<T>(
    fn: () => Promise<T>,
    maxAttempts: number,
    baseDelay = 100
): Promise<T> {
    for (let attempt = 1; attempt <= maxAttempts; attempt++) {
        try {
            return await fn();
        } catch (err) {
            if (attempt === maxAttempts) throw err;
            const delay = baseDelay * Math.pow(2, attempt - 1);
            await new Promise(resolve => setTimeout(resolve, delay));
        }
    }
    throw new Error('unreachable');
}

type Observer<T> = {
    next: (value: T) => void;
    complete?: () => void;
    error?: (err: unknown) => void;
};

class Observable<T> {
    constructor(private producer: (observer: Observer<T>) => void) {}

    subscribe(observer: Observer<T>): { unsubscribe: () => void } {
        let active = true;
        this.producer({
            next: val => active && observer.next(val),
            complete: () => { active = false; observer.complete?.(); },
            error: err => { active = false; observer.error?.(err); },
        });
        return { unsubscribe: () => { active = false; } };
    }

    map<U>(fn: (val: T) => U): Observable<U> {
        return new Observable<U>(observer =>
            this.subscribe({
                next: val => observer.next(fn(val)),
                complete: observer.complete,
                error: observer.error,
            })
        );
    }
}

class LRUCache<K, V> {
    private cache = new Map<K, V>();

    constructor(private readonly capacity: number) {}

    get(key: K): V | undefined {
        if (!this.cache.has(key)) return undefined;
        const val = this.cache.get(key)!;
        this.cache.delete(key);
        this.cache.set(key, val);
        return val;
    }

    put(key: K, value: V): void {
        if (this.cache.has(key)) this.cache.delete(key);
        this.cache.set(key, value);
        if (this.cache.size > this.capacity) {
            this.cache.delete(this.cache.keys().next().value!);
        }
    }

    get size(): number {
        return this.cache.size;
    }
}

type Middleware<T> = (ctx: T, next: () => Promise<void>) => Promise<void>;

async function compose<T>(
    middlewares: Middleware<T>[],
    ctx: T
): Promise<void> {
    async function dispatch(i: number): Promise<void> {
        if (i >= middlewares.length) return;
        await middlewares[i](ctx, () => dispatch(i + 1));
    }
    await dispatch(0);
}
